function LSdkCpSteam:OnInternalCreateOrderOk(orderData)
    local payData = orderData.payData
    local tgaData = orderData.tgaData
    local extraData = orderData.extraData
    local objJson = LxHttpHelper.CheckWebJson(CS.YXWebRet.ok,orderData.orderId)
    if (not objJson) then
        return
    end
    local sOutOrderNo = tostring(objJson.msg)
    local sSign = objJson.cp_sign

    local sMoney = tostring(payData.money * 100)
    local productName = payData.productName or ""
    local sProductDesc = productName
    local produceCpId = extraData.produceCp or ""
    local payCurrency = "USD"
    local itemId = payData.payPointRefId

    if gLxTKData then
        tgaData.orderId = sOutOrderNo
        gLxTKData:OnPayTAReq(tgaData)
    end

    local steamid = self._sUserId
    local appid = self._steamAppId --"3650520"
    local itemcount = "1"
    local language = "zh-TW" --zh-CN , en
    local usersession = "client" -- web
    local productcount = "1"
    local isSandbox = "false"

    local tokenTbl = {
        "orderid="..sOutOrderNo,
        "steamid="..steamid,
        "appid="..appid,
        "itemcount="..itemcount,
        "language="..language,
        "currency="..payCurrency,
        "usersession="..usersession,
        "itemid="..itemId,
        "qty="..productcount,
        "amount="..sMoney,
        "description="..sProductDesc,
        "isSandbox="..isSandbox,
    }

    local paramPart = table.concat(tokenTbl, "&")
    local params = "/steam/initTxn.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()

    local urlSuffix = LUtil.MakeB64SendData(params)
    GF.StartWait()
    LxHttpHelper.DoWebRequestURL(true, urlList, urlSuffix, function(ret, result, url)
        if self:IsDisposed() then return end

        GF.StopWait()

        if LOG_INFO_ENABLED then
            LXFW.LxLog.WEB(result)
        end

        if (ret == CS.YXWebRet.ok) then

        elseif ret == CS.YXWebRet.Error then

        elseif ret == CS.YXWebRet.Timeout then --超时的过几s后重新请求一次

        end
    end, true)

end

